import sys
import random

class Solution:
   def __init__(self):
      pass

   def merge(self, nums, left, mid, right):
      temp = [0] * (right - left + 1)
      i = left
      j = mid + 1
      k = 0

      while i <= mid and j <= right:
         if nums[i] >= nums[j]: 
            temp[k] = nums[i]
            i += 1
         else:
            temp[k] = nums[j]
            j += 1
         k += 1

      while i <= mid:
         temp[k] = nums[i]
         i += 1
         k += 1

      while j <= right:
         temp[k] = nums[j]
         j += 1
         k += 1

      for p in range(0, right - left + 1):
         nums[left + p] = temp[p]

   def solve(self, nums):
      self.merge_sort(nums, 0, len(nums) - 1)
      return nums

   def merge_sort(self, nums, left, right):
      if left < right:
         mid = (left + right) // 2
         self.merge_sort(nums, left, mid)
         self.merge_sort(nums, mid + 1, right)
         self.merge(nums, left, mid, right)

   def main(self):
      random.seed(0)
      n = int(input())
      nums = [random.randint(0, 1000) for _ in range(n)]
      print(' '.join([str(num) for num in self.solve(nums)]))

if __name__ == '__main__':
   Solution().main()

